import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import './App.css';
import LoginPage from './Components/Login';
import SignupPage from './Components/Signup';
import SideNav from './Components/SideNav'; // Import SideNav component

// MainPage component (added here)
function MainPage({ logout }) {
  return (
    <div>
      <h2>Welcome to the Main Page</h2>
      <button onClick={logout}>Logout</button>
    </div>
  );
}

function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false); // Manage login state

  // Handle login success (simulate login in this case)
  const login = () => {
    setIsAuthenticated(true);
  };

  // Handle logout (simulate logout)
  const logout = () => {
    setIsAuthenticated(false);
  };

  return (
    <Router>
      <div className="App">
        <h1>J-Test</h1>

        {/* Add the SideNav component here */}
        <SideNav /> {/* This is the side navigation */}

        <Routes>
          {/* Login Route */}
          <Route path="/Login" element={<LoginPage login={login} />} />
          {/* Signup Route */}
          <Route path="/Signup" element={<SignupPage />} />

          {/* MainPage Route - Only accessible if authenticated */}
          <Route
            path="/Main"
            element={isAuthenticated ? (
              <MainPage logout={logout} />
            ) : (
              <Navigate to="/Login" /> // Redirect to Login if not authenticated
            )}
          />

          {/* Default route */}
          <Route path="/" element={<Navigate to="/Login" />} />
        </Routes>
      </div>
    </Router>
  );
}

export default App;
